import React, { useState } from "react";
import "./App.css";

const FRACTIONS = [
  { numerator: 1, denominator: 2, color: "#6366F1", label: "1/2" },
  { numerator: 1, denominator: 3, color: "#10B981", label: "1/3" },
  { numerator: 1, denominator: 4, color: "#EF4444", label: "1/4" },
  { numerator: 1, denominator: 6, color: "#F59E0B", label: "1/6" },
  { numerator: 1, denominator: 8, color: "#8B5CF6", label: "1/8" },
];

const handleDragStart = (e, fraction) => e.dataTransfer.setData("fraction", JSON.stringify(fraction));

// --- 1. FREE PLAY ---
function FreePlay() {
  const [rows, setRows] = useState([[], [], []]);
  const handleDrop = (e, rowIndex) => {
    e.preventDefault();
    const data = JSON.parse(e.dataTransfer.getData("fraction"));
    const total = rows[rowIndex].reduce((s, f) => s + f.numerator / f.denominator, 0);
    if (total + (data.numerator / data.denominator) <= 1.01) {
      const nr = [...rows];
      nr[rowIndex].push({ ...data, id: Math.random() });
      setRows(nr);
    }
  };
  return (
    <div className="card">
      <p className="instruction-text">Drag blocks to make rows. Can you make them the same length? 🎈</p>
      <div className="toolbox">
        {FRACTIONS.map((f, i) => (
          <div key={i} draggable onDragStart={(e) => handleDragStart(e, f)} className="fraction-block" style={{ backgroundColor: f.color }}>{f.label}</div>
        ))}
      </div>
      {rows.map((row, i) => (
        <div key={i} className="row-container">
          <div onDragOver={(e) => e.preventDefault()} onDrop={(e) => handleDrop(e, i)} className="drop-zone">
            {row.length === 0 && <span className="drop-zone-placeholder">Row {i+1}</span>}
            {row.map((b, bi) => (
              <div key={b.id} onClick={() => { const nr = [...rows]; nr[i].splice(bi,1); setRows(nr); }} className="placed-block" style={{ width: `${(b.numerator/b.denominator)*100}%`, backgroundColor: b.color }}>{b.label}</div>
            ))}
          </div>
        </div>
      ))}
      <div style={{ textAlign: 'center' }}><button onClick={() => setRows([[],[],[]])} className="btn-danger">🗑️ Reset Board</button></div>
    </div>
  );
}

// --- 2. PIZZA ---
function PizzaMode() {
  const [slices, setSlices] = useState([]);
  let currentAngle = -90;
  return (
    <div className="card">
      <p className="instruction-text">Drag slices to build your pizza! 🍕</p>
      <div className="toolbox">
        {FRACTIONS.map((f, i) => (
          <div key={i} draggable onDragStart={(e) => handleDragStart(e, f)} className="fraction-block" style={{ backgroundColor: f.color }}>{f.label}</div>
        ))}
      </div>
      <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center' }} onDragOver={(e) => e.preventDefault()} onDrop={(e) => {
        const f = JSON.parse(e.dataTransfer.getData("fraction"));
        if (slices.reduce((s, x) => s + x.numerator/x.denominator, 0) + f.numerator/f.denominator <= 1.01) {
          setSlices([...slices, { ...f, id: Math.random() }]);
        }
      }}>
        <svg width="300" height="300" viewBox="0 0 100 100" className="pizza-svg">
          <circle cx="50" cy="50" r="48" fill="#FDE68A" stroke="#D97706" strokeWidth="2" />
          <circle cx="50" cy="50" r="42" fill="#FEF3C7" />
          {slices.map((s) => {
            const angle = (s.numerator / s.denominator) * 360;
            const x1 = 50 + 40 * Math.cos((currentAngle * Math.PI) / 180);
            const y1 = 50 + 40 * Math.sin((currentAngle * Math.PI) / 180);
            currentAngle += angle;
            const x2 = 50 + 40 * Math.cos((currentAngle * Math.PI) / 180);
            const y2 = 50 + 40 * Math.sin((currentAngle * Math.PI) / 180);
            return <path key={s.id} d={`M 50 50 L ${x1} ${y1} A 40 40 0 ${angle > 180 ? 1 : 0} 1 ${x2} ${y2} Z`} fill={s.color} stroke="white" strokeWidth="0.5" className="pizza-slice" onClick={() => setSlices(slices.filter(x => x.id !== s.id))} />;
          })}
        </svg>
        <button onClick={() => setSlices([])} className="btn-danger" style={{ marginTop: '20px' }}>New Pizza</button>
      </div>
    </div>
  );
}

// --- 3. JOURNEY ---
function JourneyMode() {
  const [journey, setJourney] = useState([]);
  const [vehicle, setVehicle] = useState("🚗");
  const total = journey.reduce((s, x) => s + x.numerator/x.denominator, 0);
  return (
    <div className="card">
      <p className="instruction-text">Help the vehicle reach the finish line! 🏁</p>
      <div style={{ textAlign: 'center', fontSize: '2rem', marginBottom: '1rem' }}>
        {['🚗', '🚲', '🏃', '🚀', '🛸'].map(v => <span key={v} onClick={() => setVehicle(v)} style={{ cursor: 'pointer', margin: '0 10px', opacity: vehicle === v ? 1 : 0.3 }}>{v}</span>)}
      </div>
      <div className="toolbox">
        {FRACTIONS.map((f, i) => (
          <div key={i} draggable onDragStart={(e) => handleDragStart(e, f)} className="fraction-block" style={{ backgroundColor: f.color }}>{f.label}</div>
        ))}
      </div>
      <div className="journey-road" onDragOver={(e) => e.preventDefault()} onDrop={(e) => {
        const f = JSON.parse(e.dataTransfer.getData("fraction"));
        if (total + f.numerator/f.denominator <= 1.01) setJourney([...journey, { ...f, id: Math.random() }]);
      }}>
        <div className="road-markings" />
        <div style={{ position: 'absolute', right: 0, height: '100%', width: '15px', background: 'repeating-linear-gradient(0deg, #000, #000 10px, #fff 10px, #fff 20px)' }} />
        {journey.map(s => <div key={s.id} style={{ height: '100%', width: `${(s.numerator/s.denominator)*100}%`, backgroundColor: s.color, opacity: 0.6 }} />)}
        <div className="vehicle" style={{ left: `${Math.min(total * 100, 100)}%` }}>{vehicle}</div>
      </div>
      <div style={{ textAlign: 'center', marginTop: '20px' }}><button onClick={() => setJourney([])} className="btn-danger">Restart</button></div>
    </div>
  );
}

// --- 4. WALL ---
function FractionWall() {
  const rows = [
    [{ l: "1 Whole", n: 1, d: 1, c: "#94A3B8" }],
    [{ l: "1/2", n: 1, d: 2, c: "#6366F1" }, { l: "1/2", n: 1, d: 2, c: "#6366F1" }],
    [{ l: "1/3", n: 1, d: 3, c: "#10B981" }, { l: "1/3", n: 1, d: 3, c: "#10B981" }, { l: "1/3", n: 1, d: 3, c: "#10B981" }],
    Array(4).fill({ l: "1/4", n: 1, d: 4, c: "#EF4444" }),
    Array(6).fill({ l: "1/6", n: 1, d: 6, c: "#F59E0B" }),
    Array(8).fill({ l: "1/8", n: 1, d: 8, c: "#8B5CF6" }),
  ];
  return (
    <div className="card">
      <p className="instruction-text">The Fraction Wall shows how parts fit together! 🧱</p>
      <div className="fraction-wall">
        {rows.map((row, i) => (
          <div key={i} className="wall-row">
            {row.map((b, j) => (
              <div key={j} className="wall-block" style={{ width: `${(b.n/b.d)*100}%`, backgroundColor: b.c }}>{b.l}</div>
            ))}
          </div>
        ))}
      </div>
    </div>
  );
}

// --- 5. BATTLE ---
function Battle() {
  const [l, setL] = useState(FRACTIONS[0]);
  const [r, setR] = useState(FRACTIONS[2]);
  const [msg, setMsg] = useState("");
  const check = (op) => {
    const lv = l.numerator/l.denominator, rv = r.numerator/r.denominator;
    let ok = op === ">" ? lv > rv : op === "<" ? lv < rv : Math.abs(lv-rv) < 0.01;
    setMsg(ok ? "🎉 Correct!" : "🤔 Try again!");
  };
  return (
    <div className="card" style={{ textAlign: 'center' }}>
      <p className="instruction-text">Which is bigger? ⚔️</p>
      <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', gap: '40px', marginBottom: '30px' }}>
        <div className="fraction-block" style={{ backgroundColor: l.color, width: '120px', height: '80px', fontSize: '2rem' }}>{l.label}</div>
        <div style={{ width: '50px', height: '50px', background: 'var(--primary)', borderRadius: '50%', color: 'white', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 'bold' }}>VS</div>
        <div className="fraction-block" style={{ backgroundColor: r.color, width: '120px', height: '80px', fontSize: '2rem' }}>{r.label}</div>
      </div>
      <div style={{ display: 'flex', justifyContent: 'center', gap: '15px' }}>
        {['>', '=', '<'].map(op => <button key={op} onClick={() => check(op)} className="btn-primary" style={{ fontSize: '2rem' }}>{op}</button>)}
      </div>
      {msg && <div style={{ marginTop: '20px' }}><h3>{msg}</h3><button onClick={() => { setL(FRACTIONS[Math.floor(Math.random()*5)]); setR(FRACTIONS[Math.floor(Math.random()*5)]); setMsg(""); }} className="btn-primary">Next Battle</button></div>}
    </div>
  );
}

// --- 6. LINE ---
function Line() {
  const [target, setTarget] = useState(0.5);
  const [pos, setPos] = useState(0.1);
  const [msg, setMsg] = useState("");
  return (
    <div className="card">
      <p className="instruction-text">Move the pin to <strong>{target === 0.5 ? "1/2" : target === 0.25 ? "1/4" : "3/4"}</strong>! 📍</p>
      <div style={{ padding: '40px 0', position: 'relative' }}>
        <div style={{ height: '4px', background: '#334155', width: '100%', position: 'relative' }}>
          {[0, 0.25, 0.5, 0.75, 1].map(t => <div key={t} style={{ position: 'absolute', left: `${t*100}%`, height: '15px', width: '2px', background: '#334155', top: '-6px' }}><span style={{ position: 'absolute', top: '20px', transform: 'translateX(-50%)', fontWeight: 'bold' }}>{t===0?"0":t===1?"1":t===0.5?"1/2":t===0.25?"1/4":"3/4"}</span></div>)}
          <div className="vehicle" style={{ left: `${pos*100}%`, fontSize: '2.5rem', top: '-40px', cursor: 'grab' }} onMouseDown={(e) => {
            const move = (m) => { const rect = e.currentTarget.parentElement.getBoundingClientRect(); setPos(Math.max(0, Math.min(1, (m.clientX - rect.left) / rect.width))); };
            const up = () => { window.removeEventListener('mousemove', move); window.removeEventListener('mouseup', up); };
            window.addEventListener('mousemove', move); window.addEventListener('mouseup', up);
          }}>📍</div>
        </div>
      </div>
      <div style={{ textAlign: 'center', marginTop: '40px' }}>
        <button onClick={() => setMsg(Math.abs(pos-target)<0.05 ? "🎯 Bullseye!" : "🤏 Try again!")} className="btn-primary">Check Spot</button>
        {msg && <p><strong>{msg}</strong></p>}
        <button onClick={() => { setTarget([0.25,0.5,0.75][Math.floor(Math.random()*3)]); setMsg(""); }} className="btn-primary" style={{ marginLeft: '10px' }}>New Spot</button>
      </div>
    </div>
  );
}

// --- 7. MATCH ---
function Match() {
  const [blocks, setBlocks] = useState([]);
  const total = blocks.reduce((s, x) => s + x.numerator/x.denominator, 0);
  return (
    <div className="card">
      <p className="instruction-text">Can you make exactly <strong>1/2</strong>? 🧩</p>
      <div className="toolbox">
        {FRACTIONS.filter(f => f.denominator > 2).map((f, i) => (
          <div key={i} draggable onDragStart={(e) => handleDragStart(e, f)} className="fraction-block" style={{ backgroundColor: f.color }}>{f.label}</div>
        ))}
      </div>
      <div onDragOver={(e) => e.preventDefault()} onDrop={(e) => {
        const f = JSON.parse(e.dataTransfer.getData("fraction"));
        if (total + f.numerator/f.denominator <= 0.51) setBlocks([...blocks, { ...f, id: Math.random() }]);
      }} className="drop-zone" style={{ width: '50%', margin: '0 auto' }}>
        {blocks.map(b => <div key={b.id} className="placed-block" style={{ width: `${(b.numerator/b.denominator)*200}%`, backgroundColor: b.color }}>{b.label}</div>)}
      </div>
      {Math.abs(total-0.5) < 0.01 && <h3 style={{ textAlign: 'center', color: 'var(--success)' }}>🎉 Perfect Match!</h3>}
      <button onClick={() => setBlocks([])} className="btn-danger" style={{ display: 'block', margin: '20px auto' }}>Reset</button>
    </div>
  );
}

// --- 8. BAKE ---
function Bake() {
  const [amount, setAmount] = useState(0);
  const add = (v) => { if (amount + v <= 1.01) setAmount(amount + v); };
  return (
    <div className="card">
      <p className="instruction-text">The recipe needs <strong>3/4</strong> cup! 🥣</p>
      <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
        <div className="mixing-bowl"><div className="bowl-fill" style={{ height: `${amount * 100}%` }} /></div>
        <div style={{ marginTop: '20px', display: 'flex', gap: '10px' }}>
          <button onClick={() => add(0.25)} className="btn-primary">Add 1/4</button>
          <button onClick={() => add(0.5)} className="btn-primary">Add 1/2</button>
        </div>
        {Math.abs(amount-0.75) < 0.01 && <h2 style={{ color: 'var(--success)' }}>🧁 Ready to Bake!</h2>}
        <button onClick={() => setAmount(0)} className="btn-danger" style={{ marginTop: '20px' }}>Empty</button>
      </div>
    </div>
  );
}

